SELECT COALESCE(SUM(total_price), 0)
FROM purchases
WHERE TRUNC(created_at) BETWEEN #{startDate} AND #{endDate}

SELECT COUNT(*)
FROM purchases
WHERE TRUNC(created_at) BETWEEN #{startDate} AND #{endDate}

